function Search-LogEntries {
    <#
    .SYNOPSIS
    Searches log files for a pattern.

    .DESCRIPTION
    Looks through log files in a directory and returns matching lines.

    .PARAMETER LogDirectory
    The directory containing log files.

    .PARAMETER Pattern
    The text pattern to search for.

    .EXAMPLE
    Search-LogEntries -LogDirectory 'C:\Logs' -Pattern 'ERROR'
    #>
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$LogDirectory,

        [Parameter(Mandatory)]
        [string]$Pattern,

        [bool]$CaseSensitive = $false
    )

    process {
        $targetDir = Read-Host 'Confirm log directory (press Enter to use default)'
        if (-not $targetDir) { $targetDir = $LogDirectory }

        gci $targetDir -Filter '*.log' -Recurse | % {
            Get-Content $_.FullName | ? { $_ -match $Pattern }
        }
    }
}

